@ExtendWith(MockitoExtension.class)
class PaymentServiceTest {

    @Mock
    PaymentGateway gateway;

    @InjectMocks
    PaymentService paymentService;

    @Test
    void shouldReturnReceipt_whenChargeSucceeds() {
        // Arrange
        PaymentRequest request = new PaymentRequest("order-1", 500);
        Receipt receipt = new Receipt("txn-99", "SUCCESS");
        when(gateway.charge(request)).thenReturn(receipt);

        // Act
        Receipt result = paymentService.pay(request);

        // Assert
        assertEquals("SUCCESS", result.status());
        verify(gateway).charge(request);
    }
}

