@ExtendWith(MockitoExtension.class)
class OrderServiceTest {

    @Mock
    OrderRepository orderRepository;
    @Mock
    InventoryClient inventoryClient;
    @Captor
    ArgumentCaptor<Order> orderCaptor;
    @InjectMocks
    OrderService orderService;

    @ParameterizedTest
    @CsvSource({"5, true", "0, false"})
    void shouldPlaceOrder_onlyWhenStockAvailable(int stock, boolean expectedSuccess) {
        when(inventoryClient.stockFor("sku-1")).thenReturn(stock);

        boolean placed = orderService.placeOrder("sku-1", 1);

        assertEquals(expectedSuccess, placed);
        if (expectedSuccess) {
            verify(orderRepository).save(orderCaptor.capture());
            assertEquals("sku-1", orderCaptor.getValue().sku());
        } else {
            verify(orderRepository, never()).save(any());
        }
    }
}

