@DataJpaTest
class OrderRepositoryTest {

    @Autowired
    OrderRepository orderRepository;

    @Test
    void shouldReturnOnlyPendingOrders() {
        orderRepository.save(new Order("order-1", "PENDING"));
        orderRepository.save(new Order("order-2", "SHIPPED"));

        List<Order> pending = orderRepository.findByStatus("PENDING");

        assertEquals(1, pending.size());
        assertEquals("order-1", pending.get(0).id());
    }
}

